import os

def validate_file_size(file_path, size_limit, unit="MB"):
    if not os.path.exists(file_path):
        return False

    actual_size_bytes = os.path.getsize(file_path)

    unit_factor = {
        "B": 1,
        "KB": 1024,
        "MB": 1024 * 1024,
        "GB": 1024 * 1024 * 1024,
    }

    try:
        limit_bytes = size_limit * unit_factor[unit.upper()]
    except KeyError:
        return False
    except TypeError:
        return False

    return actual_size_bytes <= limit_bytes
